#!/usr/bin/env bash
# ============================================================================
# Secret Guard — v{{VERSION}}
# Event: PreToolUse | Matcher: Write
# Generated by {{PROJECT_NAME}} harness-marketplace plugin
# Reads JSON from stdin (Claude Code v2 hook format)
# Exit: 0 = allow, 2 = deny (Claude sees stderr)
# ============================================================================
set -euo pipefail

# shellcheck disable=SC1091
source "$(dirname "$0")/_log.sh"
# shellcheck disable=SC1091
source "$(dirname "$0")/_parse.sh"

# ═══ GENERATED RULES (overwritten on upgrade) ═══

FILE_PATH="${TOOL_FILE_PATH:-}"
CONTENT="${TOOL_CONTENT:-}"

if [[ -z "$CONTENT" ]]; then
  # No content to check (e.g., Edit on existing file with no new content)
  exit 0
fi

FOUND_SECRETS=0
REASONS=()
MESSAGES=()

# --- Hardcoded secret patterns ---

# Generic secret assignment patterns (key=value with literal values, not env vars)
# Matches: password="literal", api_key='literal', secret=literal
# Ignores: password=$ENV_VAR, api_key=process.env.X, password=""
while IFS= read -r match; do
  if [[ -n "$match" ]]; then
    FOUND_SECRETS=1
    REASONS+=("generic-secret")
    MESSAGES+=("[SECRET] Possible hardcoded secret found: $match")
  fi
done < <(echo "$CONTENT" | grep -inE '(password|passwd|api_key|apikey|api_secret|secret_key|secret|token|access_token|auth_token)\s*[=:]\s*["\x27]?[a-zA-Z0-9+/=_\-]{8,}' | grep -ivE '(process\.env|os\.environ|\$\{|\$[A-Z_]|getenv|env\[|config\[|placeholder|example|changeme|your_|xxx|todo)' || true)

# --- AWS Access Keys ---
if echo "$CONTENT" | grep -qE 'AKIA[0-9A-Z]{16}'; then
  FOUND_SECRETS=1
  REASONS+=("aws-access-key-id")
  MESSAGES+=("[SECRET] AWS Access Key ID detected (AKIA...)")
fi

# --- AWS Secret Access Keys ---
if echo "$CONTENT" | grep -qE '["\x27][0-9a-zA-Z/+]{40}["\x27]' && echo "$CONTENT" | grep -qiE '(aws|secret|access)'; then
  FOUND_SECRETS=1
  REASONS+=("aws-secret-key")
  MESSAGES+=("[SECRET] Possible AWS Secret Access Key detected")
fi

# --- Private Keys ---
if echo "$CONTENT" | grep -qE '\-\-\-\-\-BEGIN (RSA |EC |DSA |OPENSSH )?PRIVATE KEY\-\-\-\-\-'; then
  FOUND_SECRETS=1
  REASONS+=("private-key-block")
  MESSAGES+=("[SECRET] Private key block detected")
fi

# --- GitHub / GitLab tokens ---
if echo "$CONTENT" | grep -qE '(ghp_[a-zA-Z0-9]{36}|gho_[a-zA-Z0-9]{36}|github_pat_[a-zA-Z0-9_]{82}|glpat-[a-zA-Z0-9\-]{20,})'; then
  FOUND_SECRETS=1
  REASONS+=("github-gitlab-token")
  MESSAGES+=("[SECRET] GitHub/GitLab personal access token detected")
fi

# --- Generic high-entropy strings assigned to secret-like variables ---
if echo "$CONTENT" | grep -qiE '(jwt_secret|encryption_key|signing_key|private_key)\s*[=:]\s*["\x27][^\s"'\'']{16,}'; then
  FOUND_SECRETS=1
  REASONS+=("high-value-secret")
  MESSAGES+=("[SECRET] High-value secret variable with literal value detected")
fi

# --- Report findings ---
if [[ "$FOUND_SECRETS" -eq 1 ]]; then
  reason_joined="$(IFS=,; echo "${REASONS[*]}")"
  log_block "secret-guard" "$reason_joined" "path=$FILE_PATH"
  echo "[SECRET-GUARD] Potential secrets detected in '$FILE_PATH':" >&2
  for msg in "${MESSAGES[@]}"; do
    echo "  $msg" >&2
  done
  echo "" >&2
  echo "Use environment variables or a secrets manager instead of hardcoding values." >&2
  echo "If these are intentional test fixtures, add an exception in the custom rules section." >&2
  exit 2
fi

# ═══ CUSTOM RULES BELOW (preserved on upgrade) ═══

# Add your own secret detection rules here.
# They will be preserved when the plugin is upgraded.
#
# Example:
#   if echo "$CONTENT" | grep -qE 'my_company_internal_token_prefix_[a-z0-9]+'; then
#     log_block "secret-guard" "custom-token" "path=$FILE_PATH"
#     echo "[SECRET] Custom: internal token pattern detected" >&2
#     exit 2
#   fi
#
# To allowlist a file (e.g., test fixtures):
#   case "$FILE_PATH" in
#     */test/fixtures/*) exit 0 ;;
#   esac

exit 0
